SELECT * FROM ( SELECT INNER_QRY.*, ROWNUM AS RNUM FROM ( SELECT t.TRX_ID as trxId, t.TRX_NAME as trxName, t.TRX_STOP_YN as trxStopYn, t.RETRY_TRX_YN as autoManualType, tmReq.ORG_ID as orgId, o.ORG_NAME as orgName, tmReq.MESSAGE_ID as reqMessageId, mReq.MESSAGE_NAME as reqMessageName, tmRes.MESSAGE_ID as resMessageId, mRes.MESSAGE_NAME as resMessageName, tmReq.STD_MESSAGE_ID as stdReqMessageId, mStdReq.MESSAGE_NAME as stdReqMessageName, tmRes.STD_RES_MESSAGE_ID as stdResMessageId, mStdRes.MESSAGE_NAME as stdResMessageName, NVL(tmReq.PROXY_RES_YN, tmRes.PROXY_RES_YN) as proxyResYn, NVL(tmReq.MULTI_RES_YN, tmRes.MULTI_RES_YN) as multiResYn
ORDER BY
t.TRX_ID t.TRX_NAME o.ORG_NAME t.TRX_STOP_YN t.TRX_ID
ASC DESC ASC
) INNER_QRY WHERE ROWNUM <= #{endRow} ) WHERE RNUM > #{offset}

SELECT * FROM ( SELECT INNER_QRY.*, ROWNUM AS RNUM FROM ( SELECT t.TRX_ID as trxId, t.TRX_NAME as trxName, t.OPER_MODE_TYPE as operModeType, t.TRX_TYPE as trxType, t.RETRY_TRX_YN as retryTrxYn, t.TRX_STOP_YN as trxStopYn, t.TRX_STOP_REASON as trxStopReason, COALESCE(au_cnt.accessUserCount, 0) as accessUserCount
ORDER BY
t.TRX_ID t.TRX_NAME t.OPER_MODE_TYPE t.TRX_TYPE t.TRX_STOP_YN t.TRX_ID
ASC DESC ASC
) INNER_QRY WHERE ROWNUM <= #{endRow} ) WHERE RNUM > #{offset}
